function photoUrl(p, size) {
  if (p.startsWith("https://")) {
    const base = size === "full" ? CL_FULL : CL_THUMB;
    return base + encodeURIComponent(p);
  }
  return PHOTOS_BASE ? PHOTOS_BASE + p : null; // local — need CDN
}

